**Changes**:

1. Import `AppThemeId`, `APP_THEMES_BY_ID`, `DEFAULT_APP_THEME_ID` from `@t3tools/shared/theme`

2. Add constants:
   ```ts
   const APP_THEME_STORAGE_KEY = "t3code:app-theme"
   ```

3. Add helpers:
   ```ts
   function getStoredAppTheme(): AppThemeId {
     const raw = localStorage.getItem(APP_THEME_STORAGE_KEY)
     if (raw === "t3-light" || raw === "t3-dark" || raw === "t3-midnight") return raw
     return DEFAULT_APP_THEME_ID
   }

   function applyAppTheme(themeId: AppThemeId, suppressTransitions = false) {
     document.documentElement.setAttribute("data-theme", themeId)
     const isDark = APP_THEMES_BY_ID[themeId].isDark
     applyTheme(isDark ? "dark" : "light", suppressTransitions)
   }
   ```

4. Extend `ThemeSnapshot`:
   ```ts
