     theme: Theme
     systemDark: boolean
     appThemeId: AppThemeId
   }
   ```

5. Extend `getSnapshot()` to include `appThemeId`

6. Extend `subscribe()`'s `handleStorage` to also react to `APP_THEME_STORAGE_KEY`

7. Module-level init (add after existing `applyTheme(getStored())`):
   ```ts
   applyAppTheme(getStoredAppTheme())
   ```

8. Add `setAppTheme` to `useTheme`:
   ```ts
   const setAppTheme = useCallback((id: AppThemeId) => {
     localStorage.setItem(APP_THEME_STORAGE_KEY, id)
     applyAppTheme(id, true)
     emitChange()
   }, [])
   ```

9. Update `resolvedTheme` derivation — instead of reading from `snapshot.theme`, read from the app theme's `isDark`:
   ```ts
   const resolvedTheme: "light" | "dark" = APP_THEMES_BY_ID[snapshot.appThemeId].isDark
     ? "dark"
     : "light"
   ```

10. Return: `{ theme, setTheme, resolvedTheme, appThemeId, setAppTheme } as const`

---

### 4. `apps/web/src/index.css`

**Add new default CSS vars** into the existing `:root` block (before the `@variant dark` block):
```css
/* Named theme slots — overridden by [data-theme] blocks below */
