  --editor-bg: oklch(0.99 0 0);
  --terminal-bg: oklch(0.13 0 0);
  --status-bar-bg: oklch(0.488 0.217 264);
}

[data-theme="t3-dark"] {
  color-scheme: dark;
  --background: oklch(0.115 0.005 264);
  --foreground: oklch(0.9 0 0);
  --primary: oklch(0.588 0.217 264);
  --ring: oklch(0.588 0.217 264);
  --sidebar-bg: oklch(0.135 0.005 264);
  --editor-bg: oklch(0.105 0.005 264);
  --terminal-bg: oklch(0.07 0.003 264);
  --status-bar-bg: oklch(0.488 0.217 264);
}

[data-theme="t3-midnight"] {
  color-scheme: dark;
  --background: oklch(0.10 0.025 265);
  --foreground: oklch(0.92 0.01 220);
  --primary: oklch(0.65 0.22 285);
  --ring: oklch(0.65 0.22 285);
  --sidebar-bg: oklch(0.08 0.025 265);
  --editor-bg: oklch(0.11 0.025 265);
  --terminal-bg: oklch(0.05 0.025 265);
  --status-bar-bg: oklch(0.48 0.22 285);
}
