import { APP_THEME_IDS, APP_THEMES_BY_ID } from "@t3tools/shared/theme";
import { useTheme } from "~/hooks/useTheme";

/**
 * A grid of theme cards with colour-preview swatches.
 * Each card shows three colour strips — background, sidebar, and accent — so
 * users can distinguish the palettes at a glance before selecting one.
 */
export function ThemeSelector() {
  const { appThemeId, setAppTheme } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {APP_THEME_IDS.map((id) => {
        const themeData = APP_THEMES_BY_ID[id];
        const selected = appThemeId === id;
        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setAppTheme(id)}
            className={`flex flex-col gap-2 rounded-xl border px-3 py-3 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent"
            }`}
          >
            {/* Colour preview — three vertical strips */}
            <div
              className="flex h-10 w-full overflow-hidden rounded-lg border border-border/60"
              aria-hidden="true"
            >
              {/* Background swatch — widest, represents the main surface */}
              <span className="flex-1" style={{ backgroundColor: themeData.colors.background }} />
              {/* Sidebar swatch — narrow strip on the right edge */}
              <span className="w-3" style={{ backgroundColor: themeData.colors.sidebar }} />
              {/* Accent swatch — coloured sliver for brand colour */}
              <span className="w-4" style={{ backgroundColor: themeData.colors.accent }} />
            </div>

            {/* Theme label row */}
            <div className="flex items-center justify-between gap-1">
              <span className="text-xs font-medium text-foreground">{themeData.name}</span>
              {selected && (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  On
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

