/** Identifier for each built-in application colour theme. */
export type AppThemeId = "t3-light" | "t3-dark" | "t3-midnight"

/**
 * Colour slots that every built-in theme must define.
 * These values are used both as CSS custom-property values (applied via
 * `[data-theme]` CSS blocks) and as raw colour strings for preview swatches.
 */
export interface AppThemeColors {
  /** Main page background — maps to `--background`. */
  background: string
  /** Primary text colour — maps to `--foreground`. */
  foreground: string
  /** Brand / interactive accent colour — maps to `--primary`. */
  accent: string
  /** Sidebar panel background — maps to `--sidebar-bg`. */
  sidebar: string
  /** Editor surface background — maps to `--editor-bg`. */
  editor: string
  /** Terminal surface background — maps to `--terminal-bg`. */
  terminal: string
  /** Status-bar background — maps to `--status-bar-bg`. */
  statusBar: string
}

/** A fully-described built-in theme, including metadata and colour slots. */
export interface AppTheme {
  id: AppThemeId
  name: string
  /** Whether to activate dark-mode Tailwind variants (`.dark` class). */
  isDark: boolean
  colors: AppThemeColors
}

/**
 * All built-in themes keyed by their ID.
 *
 * Using a `Record` (not an array) keeps per-theme lookup O(1) and satisfies
 * the `noUncheckedIndexedAccess` compiler flag without null-checks at every
 * call-site — `id: AppThemeId` is always a valid key.
 */
export const APP_THEMES_BY_ID: Record<AppThemeId, AppTheme> = {
  "t3-light": {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "oklch(1 0 0)",
      foreground: "oklch(0.2 0 0)",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "oklch(0.965 0 0)",
      editor: "oklch(0.99 0 0)",
      terminal: "oklch(0.13 0 0)",
      statusBar: "oklch(0.488 0.217 264)",
    },
  },
  "t3-dark": {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "oklch(0.115 0.005 264)",
      foreground: "oklch(0.9 0 0)",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "oklch(0.135 0.005 264)",
      editor: "oklch(0.105 0.005 264)",
      terminal: "oklch(0.07 0.003 264)",
      statusBar: "oklch(0.488 0.217 264)",
    },
  },
  "t3-midnight": {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "oklch(0.10 0.025 265)",
      foreground: "oklch(0.92 0.01 220)",
      accent: "oklch(0.65 0.22 285)",
      sidebar: "oklch(0.08 0.025 265)",
      editor: "oklch(0.11 0.025 265)",
      terminal: "oklch(0.05 0.025 265)",
      statusBar: "oklch(0.48 0.22 285)",
    },
  },
}

/** Ordered list of all theme IDs — use for rendering theme pickers. */
export const APP_THEME_IDS: readonly AppThemeId[] = ["t3-light", "t3-dark", "t3-midnight"]

/** The theme applied when no preference has been stored yet. */
export const DEFAULT_APP_THEME_ID: AppThemeId = "t3-dark"

