import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  APP_THEMES_BY_ID,
  DEFAULT_APP_THEME_ID,
  type AppThemeId,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type Theme = "light" | "dark" | "system";

type ThemeSnapshot = {
  theme: Theme;
  systemDark: boolean;
  appThemeId: AppThemeId;
};

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";
const APP_THEME_STORAGE_KEY = "t3code:app-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// Module-level store (shared across all hook instances via useSyncExternalStore)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

// ---------------------------------------------------------------------------
// Helpers — light / dark class
// ---------------------------------------------------------------------------

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): Theme {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = theme === "dark" || (theme === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// Helpers — named app theme
// ---------------------------------------------------------------------------

function getStoredAppTheme(): AppThemeId {
  const raw = localStorage.getItem(APP_THEME_STORAGE_KEY);
  if (raw === "t3-light" || raw === "t3-dark" || raw === "t3-midnight") return raw;
  return DEFAULT_APP_THEME_ID;
}

/**
 * Apply a named app theme by:
 * 1. Setting `data-theme` on `<html>` (activates the matching CSS block).
 * 2. Syncing the `.dark` class so Tailwind dark-variant utilities work.
 */
function applyAppTheme(themeId: AppThemeId, suppressTransitions = false) {
  document.documentElement.setAttribute("data-theme", themeId);
  const isDark = APP_THEMES_BY_ID[themeId].isDark;
  applyTheme(isDark ? "dark" : "light", suppressTransitions);
}

// Apply both systems immediately on module load to prevent flash
applyTheme(getStored());
applyAppTheme(getStoredAppTheme());

// ---------------------------------------------------------------------------
// useSyncExternalStore glue
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const theme = getStored();
  const appThemeId = getStoredAppTheme();
  const systemDark = theme === "system" ? getSystemDark() : false;

  if (
    lastSnapshot !== null &&
    lastSnapshot.theme === theme &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.appThemeId === appThemeId
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { theme, systemDark, appThemeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    } else if (e.key === APP_THEME_STORAGE_KEY) {
      applyAppTheme(getStoredAppTheme(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { theme, appThemeId } = snapshot;

  /** Resolved light/dark mode — derived from the active app theme. */
  const resolvedTheme: "light" | "dark" = APP_THEMES_BY_ID[appThemeId].isDark ? "dark" : "light";

  /** Change the base light/dark/system preference (legacy API kept for compat). */
  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  /** Select a named app theme. Also syncs the `.dark` class and `data-theme`. */
  const setAppTheme = useCallback((id: AppThemeId) => {
    localStorage.setItem(APP_THEME_STORAGE_KEY, id);
    applyAppTheme(id, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyAppTheme(appThemeId);
  }, [appThemeId]);

  return { theme, setTheme, resolvedTheme, appThemeId, setAppTheme } as const;
}

